parameters.jsCode:
const trigger = $('Chat Webhook').first().json;
const message = trigger.body.message || '';
const sessionId = trigger.body.session_id || 'default';

// Build chat history from last 10 messages (they come DESC, reverse them)
const historyRows = $input.all().filter(function(item) { return item.json.role; });
const history = [];
for (var i = historyRows.length - 1; i >= 0; i--) {
  history.push({ role: historyRows[i].json.role, content: historyRows[i].json.content });
}

// Add current user message
history.push({ role: 'user', content: message });

return [{ json: {
  message: message,
  session_id: sessionId,
  history: history,
  history_count: history.length
} }];

